  ('5160c577-a684-4a9c-ae07-655e284b284d', '22222222-2222-2222-2222-222222222222', 'Games at the Hangout', 'Join us for Games at the Hangout 🎲 Every Monday at 1:30 PM at 99 Ottawa Street South. Drop in for board games, cards, and good conversation. Come with a friend or meet someone new. Everyone is welcome!', 'Join us for Games at the Hangout 🎲 Every Monday at 1:30 PM at 99 Ottawa Street South. Drop in for board games, cards, and good conversation. Come with a friend or meet someone new. Everyone is welcome!', ARRAY['social','sports']::event_category[], '2026-07-20T13:30:00-04:00', '2026-07-20T15:00:00-04:00', 'free', NULL, NULL, NULL, NULL, 'The Hangout: 99 Ottawa Street South, Kitchener, Ontario', ARRAY['low_cost']::accommodation_tag[], 'not_yet_verified', 'form'),
  ('9d57f958-c6d3-49a9-a758-7860e4ad1aaa', '22222222-2222-2222-2222-222222222222', 'Coffee Club In-Person - Food Truck Frenzy at Forest Hill United Church', 'This drop-in social group is open to people with disabilities who are aged 16 and older. Food Truck Frenzy at Forest Hill United Church (121 Westmount Rd. E, Kitchener). Bring cash, a chair, and maybe an umbrella! In addition to in-person events, Coffee Club also meets virtually every Thursday from 3 to 4 pm. During these Zoom calls, participants talk, laugh, and sometimes watch YouTube videos together. If you are interested in learning more information about Coffee Club or in getting the weekly Zoom link, please call Coffee Club''s facilitator, Carmen Sutherland, at 519-500-7153, or email her at carmen.sutherland@wrfn.info.', 'This drop-in social group is open to people with disabilities who are aged 16 and older. Food Truck Frenzy at Forest Hill United Church (121 Westmount Rd. E, Kitchener). Bring cash, a chair, and maybe an umbrella! In addition to in-person events, Coffee Club also meets virtually every Thursday from 3 to 4 pm. During these Zoom calls, participants talk, laugh, and sometimes watch YouTube videos together. If you are interested in learning more information about Coffee Club or in getting the weekly Zoom link, please call Coffee Club''s facilitator, Carmen Sutherland, at 519-500-7153, or email her at carmen.sutherland@wrfn.info.', ARRAY['social','arts','food']::event_category[], '2026-07-20T17:30:00-04:00', '2026-07-20T19:30:00-04:00', 'paid', NULL, NULL, NULL, NULL, '121 Westmount RD E, Kitchener', ARRAY[]::accommodation_tag[], 'not_yet_verified', 'form') /* shared community calendar */,
