  ('3c1708a7-b2f2-4d59-a05a-0f11b2ffee34', '22222222-2222-2222-2222-222222222222', 'The Hangout', 'The Hangout is a community hangout space where everyone is welcome! No purchase necessary, but we have coffee, tea, other drinks, and snacks to buy. The space is inviting and comfortable and a place where everyone is welcome! Open Tuesday and Thursdays from 8:30 am - 11:00 am', 'The Hangout is a community hangout space where everyone is welcome! No purchase necessary, but we have coffee, tea, other drinks, and snacks to buy. The space is inviting and comfortable and a place where everyone is welcome! Open Tuesday and Thursdays from 8:30 am - 11:00 am', ARRAY['social','food']::event_category[], '2026-07-23T11:00:00-04:00', '2026-07-23T14:00:00-04:00', 'free', NULL, NULL, NULL, NULL, 'Grant''s Cafe - 99 Ottawa St. S, Kitchener', ARRAY['low_cost']::accommodation_tag[], 'not_yet_verified', 'form'),
